<?php
namespace Tests\Feature;
use App\Domain\Hunts\HuntCombatEventPersister;use App\Domain\Hunts\Playback\HuntingPlaybackResult;use App\Domain\Hunts\Sessions\HuntingSessionService;use App\Models\Character;use App\Models\Hunt;use App\Models\HuntCombatEvent;use App\Models\HuntEnemy;use App\Models\HuntReward;use App\Models\HuntingSession;use App\Models\User;use App\Models\Zone;use Carbon\CarbonImmutable;use Database\Seeders\WorldCatalogSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use RuntimeException;use Tests\TestCase;
class HuntCombatEventAtomicityTest extends TestCase{use RefreshDatabase;public function test_event_failure_rolls_back_session_hunt_enemies_events_and_rewards(){$this->seed(WorldCatalogSeeder::class);CarbonImmutable::setTestNow('2026-07-12 12:00:00');$this->app->bind(HuntCombatEventPersister::class,function(){return new class extends HuntCombatEventPersister{public function persist(Hunt $hunt,HuntingPlaybackResult $playback,array $participants){throw new RuntimeException('Injected event persistence failure.');}};});$character=Character::factory()->for(User::factory())->create(['base_attack'=>500]);$zone=Zone::where('code','grey_oak_forest')->firstOrFail();$service=app(HuntingSessionService::class);$session=HuntingSession::find($service->start($character,$zone)->id());$before=$session->toArray();try{$service->tick($character,$session);$this->fail('Expected event failure.');}catch(RuntimeException $exception){$this->assertSame('Injected event persistence failure.',$exception->getMessage());}$this->assertSame(0,Hunt::count());$this->assertSame(0,HuntEnemy::count());$this->assertSame(0,HuntCombatEvent::count());$this->assertSame(0,HuntReward::count());$after=$session->fresh();$this->assertSame($before['hunts_count'],$after->hunts_count);$this->assertSame($before['victories_count'],$after->victories_count);$this->assertTrue(CarbonImmutable::parse($before['next_encounter_at'])->equalTo($after->next_encounter_at));CarbonImmutable::setTestNow();}}
